const items = $input.all();
const images = [];

for (let i = 0; i < items.length; i++) {
  try {
    const binaryKey = 'data';

    if (items[i].binary && items[i].binary[binaryKey]) {
      const binaryObject = items[i].binary[binaryKey];

      // Считываем файл и кодируем в Base64
      const buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);
      const base64String = buffer.toString('base64');

      // Добавляем в массив для Gemini
      images.push({
        inlineData: {
          mimeType: binaryObject.mimeType,
          data: base64String
        }
      });
    }
  } catch (error) {
    console.error('Error processing image:', error);
  }
}

// Возвращаем один объект со всеми изображениями
return [{
  json: {
    images: images,
    imageCount: images.length
  }
}];

const setParamsData = $('Set Params').first().json;
const photos = setParamsData.tg?.photo || [];

if (photos.length > 0) {
  const bestPhoto = photos[photos.length - 1]; // лучшее качество
  // const bestPhoto = photos[0]; // ← первый элемент = минимальное разрешение


  return [{
    json: {
      file_id: bestPhoto.file_id,
      width: bestPhoto.width,
      height: bestPhoto.height,
      file_size: bestPhoto.file_size,
      tg: setParamsData.tg
    }
  }];
}

return [{ json: { error: 'No photos found' } }];

// Создаем массив для результатов
const results = [];

// Получаем все входящие элементы
const items = $input.all();

for (const item of items) {
  try {
    // Безопасно получаем массив изображений
    const images = item.json.choices?.[0]?.message?.images;

    if (images && Array.isArray(images) && images.length > 0) {

      // 1. Получаем количество картинок
      const totalImages = images.length;

      // 2. Берем ТОЛЬКО ПЕРВУЮ картинку
      const firstImage = images[0];
      const dataUrl = firstImage.image_url?.url;

      if (dataUrl) {
        // Разбиваем Data URL для получения чистого Base64 и типа файла
        const splitData = dataUrl.split(',');
        const base64Data = splitData[1];

        // Определяем mime-type (например, image/jpeg)
        const mimeType = splitData[0].match(/:(.*?);/)?.[1] || 'image/png';
        // Определяем расширение файла
        const extension = mimeType.split('/')[1] || 'png';

        // Генерируем имя файла
        const fileName = `generated_image_1.${extension}`;

        // Формируем выходной элемент
        results.push({
          json: {
            ...item.json, // Сохраняем все исходные данные
            images_count: totalImages, // Добавляем количество картинок (число)
            info_message: `Всего сгенерировано изображений: ${totalImages}. Возвращаю первое.`,
            usage: $input.first().json.usage
          },
          binary: {
            data: {
              data: base64Data,
              mimeType: mimeType,
              fileName: fileName
            }
          }
        });
      }
    } else {
      // Если картинок нет, возвращаем исходный элемент с ошибкой
      item.json.error = "Картинки не найдены в ответе API";
      results.push(item);
    }
  } catch (error) {
    // Логируем ошибку в выходной JSON
    item.json.error_message = error.message;
    results.push(item);
  }
}

return results;

const input = $input.first();
let prompt = $('Set Params').first().json.tg?.text || "Опиши эти картинки. Ответь на русском языке.";
// Можно добавить инструкции
// prompt = `${prompt}\n\nОтветь на русском языке.`;

const images = input.json.images || [];

// Формируем content
const content = [
  { type: "text", text: prompt }
];

for (const img of images) {
  content.push({
    type: "image_url",
    image_url: {
      url: `data:${img.inlineData.mimeType};base64,${img.inlineData.data}`
    }
  });
}

return [{
  json: {
    model: $('Set User Params').first().json.tg.model,
    messages: [
      {
        role: "user",
        content: content
      },
    ],
    response_format: {
      type: "image",
      image: {
        n: 1,   // <-- ВОТ ЭТО количество картинок
        aspect_ratio: "4:3"
      }
    },
    //reasoning: {
    //    effort: "none"
    //},
    generation_config: {
      candidate_count: 1
    }
  }
}];

const raw = $('Set Params').first().json.tg?.text || 'Сгенерируй красивое кинематографичное видео';
const prompt = `${raw}, smooth motion, stable camera, cinematic lighting`;

const inlineData = $input.first().json.images?.[0]?.inlineData?.data;
const payload = {
  model: 'MiniMax-Hailuo-02',
  // model: 'T2V-01',
  prompt,
  duration: 6,
  resolution: '768P',
  prompt_optimizer: true,
};

// Если изображение есть — генерируем i2v, иначе делаем t2v.
if (inlineData) {
  payload.first_frame_image = `data:image/jpeg;base64,${inlineData}`;
}

return [{ json: payload }];

const input = $input.first().json;

if (input?.file?.download_url) {
  return [{
    json: {
      video_url: input.file.download_url,
      info_message: 'Видео готово.'
    }
  }];
}

if (input?.download_url) {
  return [{
    json: {
      video_url: input.download_url,
      info_message: 'Видео готово.'
    }
  }];
}

const statusMsg = input?.base_resp?.status_msg || '';
return [{ json: { error: statusMsg || 'Не удалось получить ссылку на видео из MiniMax API' } }];

const items = $input.all();
const retries = (items[0].json._fal_retries || 0) + 1;
const total = 4;

if (retries > total) {
  throw new Error('Timeout: видео не сгенерировано, попробуйте позже.');
}

const ratio = retries / total;
const percent = Math.min(100, Math.floor(ratio * 100));
const filled = Math.min(10, Math.floor(ratio * 10));
const bar = '█'.repeat(filled) + '░'.repeat(10 - filled);

return items.map(item => ({
  json: {
    ...item.json,
    _fal_retries: retries,
    _progress_text: `⏳ Генерация видео...\n${bar} ${percent}%`
  }
}));
